module div_8bit (
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);

    reg [7:0] SR;
    reg [7:0] NEG_DIVISOR;
    reg [3:0] cnt;
    reg start_cnt;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            res_valid <= 0;
            result <= 0;
            cnt <= 0;
            start_cnt <= 0;
        end
        else if (opn_valid && !res_valid) begin
            if (sign) begin
                if (dividend[7] == divisor[7]) begin
                    SR <= {1'b0, dividend};
                    NEG_DIVISOR <= ~{1'b0, divisor} + 1;
                end
                else begin
                    SR <= {1'b0, dividend};
                    NEG_DIVISOR <= {1'b0, divisor};
                end
            end
            else begin
                SR <= {1'b0, dividend};
                NEG_DIVISOR <= {1'b0, divisor};
            end
            cnt <= 1;
            start_cnt <= 1;
        end
        else if (start_cnt) begin
            if (cnt == 8) begin
                cnt <= 0;
                start_cnt <= 0;
                result <= {SR[7:0], 8'b0};
            end
            else begin
                cnt <= cnt + 1;
                {SR, NEG_DIVISOR} <= {SR[6:0], NEG_DIVISOR[7:1]};
                if (SR[7] == 0) begin
                    SR[7:0] <= SR[7:0] + NEG_DIVISOR;
                    SR[0] <= 1;
                end
                else begin
                    SR[0] <= 0;
                end
            end
        end
        else if (res_valid && res_ready) begin
            res_valid <= 0;
        end
        else begin
            res_valid <= res_valid;
        end
    end

endmodule
